        select_action.history = []

    select_action.history.append((ball_x, ball_y))
    if len(select_action.history) > 10:
        select_action.history.pop(0)

    if len(select_action.history) < 4:
        if ball_x < paddle_x:
            return 3
        elif ball_x > paddle_x:
            return 2
        return 0

    dx_avg = 0.0
    dy_avg = 0.0
    for i in range(1, len(select_action.history)):
        dx_avg += select_action.history[i][0] - select_action.history[i-1][0]
        dy_avg += select_action.history[i][1] - select_action.history[i-1][1]
    n = len(select_action.history) - 1
    dx_avg /= n
    dy_avg /= n

    if dy_avg < 0:
        sim_x = float(ball_x)
        sim_y = float(ball_y)
        vx = dx_avg
        vy = abs(dy_avg)
        while sim_y < 192:
            sim_y += vy
            sim_x += vx
            if sim_y > 210:
                sim_y = 210 - (sim_y - 210)
                vy = -vy
            if sim_x < 0:
                sim_x = -sim_x
                vx = -vx
            elif sim_x > 160:
                sim_x = 320 - sim_x
                vx = -vx
        target_x = int(sim_x)
    else:
        target_x = ball_x

    blend = 0.3 * ball_x + 0.7 * target_x
    distance = abs(blend - paddle_x)
    danger = max(0, 1.0 - ball_y / 210.0)
    deadband = int(15 + 35 * danger)

    if distance > deadband:
        if blend < paddle_x:
            return 3
        else:
            return 2
    return 0

