        return 1

    ball_x = obs[99]
    ball_y = obs[101]
    paddle_x = obs[72]

    # Persistent state for velocity and last action
    if not hasattr(select_action, "prev_ball_x"):
        select_action.prev_ball_x = ball_x
        select_action.prev_ball_y = ball_y
        select_action.last_action = 0
        # Initialize zones
        select_action.zone = 0  # 0=left, 1=center, 2=right
        select_action.zone_hysteresis = 0

    dx = ball_x - select_action.prev_ball_x
    dy = ball_y - select_action.prev_ball_y
    select_action.prev_ball_x = ball_x
    select_action.prev_ball_y = ball_y

    # Determine ball's horizontal direction
    if dx > 0:
        direction = 1  # moving right
    elif dx < 0:
        direction = -1  # moving left
    else:
        direction = 0

    # Predict which zone the ball will reach based on direction and y
    # Use a simple lane assignment: 3 zones of ~20 pixels each
    if ball_y < 70:
        # Ball high — use direction to anticipate
        if direction == 1:
            predicted_zone = 2  # right
        elif direction == -1:
            predicted_zone = 0  # left
        else:
            predicted_zone = 1  # center
    elif ball_y < 140:
        # Ball mid — use direction with bias
        if direction == 1:
            predicted_zone = 2
        elif direction == -1:
            predicted_zone = 0
        else:
            predicted_zone = 1
    else:
        # Ball low — use direct ball_x
        if ball_x < 53:
            predicted_zone = 0
        elif ball_x > 107:
            predicted_zone = 2
        else:
            predicted_zone = 1

    # Hysteresis: if same zone as before, strengthen; else switch slowly
    if predicted_zone == select_action.zone:
        select_action.zone_hysteresis = min(5, select_action.zone_hysteresis + 1)
    else:
        select_action.zone_hysteresis -= 1
        if select_action.zone_hysteresis <= 0:
            select_action.zone = predicted_zone
            select_action.zone_hysteresis = 2

    # Map zone to target paddle position
    zone_centers = [55, 95, 135]  # left, center, right
    target = zone_centers[select_action.zone]

    # Deadband with momentum bias
    diff = target - paddle_x
    if diff > 8:
        action = 2  # RIGHT
    elif diff < -8:
        action = 3  # LEFT
    else:
        action = 0  # NOOP

    # Avoid oscillation: if same as last action and diff small, NOOP
    if action != 0 and action == select_action.last_action and abs(diff) < 15:
        action = 0

    select_action.last_action = action
    return action

